-- ============================================
-- Legislacao full-site: luciano-zucco / Camara Dados Abertos / projetos_lei
-- Coverage ampliado parcial: Lote A autoria principal Camara
-- ============================================
-- Fonte oficial: Camara dos Deputados - Dados Abertos
--   https://dadosabertos.camara.leg.br/api/v2/deputados/220552
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}/autores
--
-- Artefato de auditoria:
--   fonte interna de curadoria
--
-- Coverage:
--   coverage_id    = luciano-zucco-camara-autoria-principal-ampliado-parcial-lote-a-20260506
--   coverage_scope = inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506
--
-- Filtro factual: das 199 rows Camara legacy existentes, somente 67
-- foram marcadas com coverage_id porque a API oficial confirmou
-- idDeputado=220552, tipo Deputado(a), ordemAssinatura=1.
-- 132 rows permanecem sem coverage por coautoria/sem autoria verificavel.
--
-- Esta migration NAO escreve em legislacao_mandato_executivo.
-- Esta migration NAO insere, deleta ou trunca rows.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  total_pl int;
  target_present int;
  target_with_other_coverage int;
  lme_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'luciano-zucco';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'luciano-zucco: candidato ausente neste banco local/CI minimo; coverage Camara pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO total_pl FROM projetos_lei WHERE candidato_id = cand_id;
  IF total_pl <> 199 THEN
    RAISE EXCEPTION 'Pre-condicao luciano-zucco: esperadas 199 rows legacy em projetos_lei, encontradas %', total_pl;
  END IF;

  SELECT count(*) INTO target_present
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND fonte = 'Camara'
    AND proposicao_id_api IN ('2481769', '2593336', '2607619', '2586613', '2584019', '2607621', '2594098', '2586688', '2593381', '2570875', '2605325', '2593380', '2593346', '2612326', '2605258', '2601137', '2593337', '2593225', '2583322', '2583320', '2579809', '2579683', '2573582', '2573475', '2567696', '2566472', '2583333', '2583316', '2581216', '2570662', '2594103', '2583328', '2583313', '2580904', '2583344', '2583318', '2581434', '2579112', '2573253', '2566810', '2583324', '2583309', '2568087', '2586388', '2583323', '2583292', '2579932', '2575724', '2568006', '2583327', '2583312', '2580559', '2577886', '2571501', '2568101', '2566741', '2583325', '2583311', '2580169', '2577880', '2571490', '2568088', '2579697', '2570883', '2583321', '2573476', '2614060');
  IF target_present <> 67 THEN
    RAISE EXCEPTION 'Pre-condicao luciano-zucco: esperadas 67 rows alvo Camara presentes, encontradas %', target_present;
  END IF;

  SELECT count(*) INTO target_with_other_coverage
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('2481769', '2593336', '2607619', '2586613', '2584019', '2607621', '2594098', '2586688', '2593381', '2570875', '2605325', '2593380', '2593346', '2612326', '2605258', '2601137', '2593337', '2593225', '2583322', '2583320', '2579809', '2579683', '2573582', '2573475', '2567696', '2566472', '2583333', '2583316', '2581216', '2570662', '2594103', '2583328', '2583313', '2580904', '2583344', '2583318', '2581434', '2579112', '2573253', '2566810', '2583324', '2583309', '2568087', '2586388', '2583323', '2583292', '2579932', '2575724', '2568006', '2583327', '2583312', '2580559', '2577886', '2571501', '2568101', '2566741', '2583325', '2583311', '2580169', '2577880', '2571490', '2568088', '2579697', '2570883', '2583321', '2573476', '2614060')
    AND coverage_id IS NOT NULL
    AND coverage_id <> 'luciano-zucco-camara-autoria-principal-ampliado-parcial-lote-a-20260506';
  IF target_with_other_coverage <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao luciano-zucco: % rows alvo ja tem coverage_id divergente', target_with_other_coverage;
  END IF;

  SELECT count(*) INTO lme_count FROM legislacao_mandato_executivo WHERE candidato_id = cand_id;
  IF lme_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao luciano-zucco: legislacao_mandato_executivo deve permanecer 0, encontrado %', lme_count;
  END IF;
END $$;

